import grpc
from concurrent import futures
import logging
from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2, code_pb2

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens=None, required_headers=None):
        self.authorized_tokens = authorized_tokens or {"valid-token-123", "admin-token-456"}
        self.required_headers = required_headers or []

    def Check(self, request, context):
        logger.info("Received authorization check request")
        
        http_request = request.attributes.request.http
        headers = http_request.headers
        
        logger.info(f"Request path: {http_request.path}")
        logger.info(f"Request method: {http_request.method}")
        logger.info(f"Headers: {dict(headers)}")
        
        for required_header in self.required_headers:
            if required_header not in headers:
                logger.warning(f"Missing required header: {required_header}")
                return self._create_denied_response(
                    f"Missing required header: {required_header}",
                    http_status_pb2.Unauthorized
                )
        
        auth_header = headers.get("authorization", "")
        
        if not auth_header:
            logger.warning("No authorization header provided")
            return self._create_denied_response(
                "Authorization header is required",
                http_status_pb2.Unauthorized
            )
        
        token = self._extract_token(auth_header)
        
        if token not in self.authorized_tokens:
            logger.warning(f"Invalid token: {token}")
            return self._create_denied_response(
                "Invalid or unauthorized token",
                http_status_pb2.Forbidden
            )
        
        logger.info("Authorization successful")
        return self._create_ok_response(headers)

    def _extract_token(self, auth_header):
        if auth_header.startswith("Bearer "):
            return auth_header[7:]
        return auth_header

    def _create_ok_response(self, request_headers):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header={"key": "x-auth-status", "value": "authorized"}
            )
        )
        
        user_id = request_headers.get("x-user-id", "unknown")
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header={"key": "x-authenticated-user", "value": user_id}
            )
        )
        
        return response

    def _create_denied_response(self, message, http_status_code):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.PERMISSION_DENIED
        response.status.message = message
        
        response.denied_response.status.code = http_status_code
        
        response.denied_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header={"key": "x-auth-status", "value": "denied"}
            )
        )
        
        response.denied_response.body = message
        
        return response


def serve(port=50051, max_workers=10):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=max_workers))
    
    auth_service = AuthorizationService(
        authorized_tokens={"valid-token-123", "admin-token-456", "user-token-789"},
        required_headers=[]
    )
    
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
        auth_service, server
    )
    
    server.add_insecure_port(f"[::]:{port}")
    
    logger.info(f"Starting Envoy External Authorization server on port {port}")
    server.start()
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(0)


if __name__ == "__main__":
    serve()